async function insertBatch<T extends Record<string, unknown>>(table: string, rows: T[], batchSize = 50): Promise<number> {
  let inserted = 0;
  for (let i = 0; i < rows.length; i += batchSize) {
    const batch = rows.slice(i, i + batchSize);
    const { error } = await supabaseQuery(table, {
      method: 'POST',
      body: batch,
    });
    if (error) {
      console.error(`Error inserting into ${table} (batch ${i}):`, error);
      throw new Error(`Failed to insert into ${table}: ${error}`);
    }
    inserted += batch.length;
  }
  return inserted;
}

export default async function handler(req: VercelRequest, res: VercelResponse) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed. Use POST to seed.' });
  }

  try {
    // Check if already seeded (idempotent)
    const { data: existingUsers } = await supabaseQuery<unknown[]>('users', { select: 'id' });
    if (Array.isArray(existingUsers) && existingUsers.length > 0) {
      return res.status(200).json({
        message: 'Database already seeded. Skipping.',
        counts: { users: existingUsers.length },
      });
    }

    // 1. Insert users
    const userCount = await insertBatch('users', USERS);

    // 2. Insert requests
    const requestCount = await insertBatch('requests', REQUESTS);

    // 3. Insert stage_history
    const stageCount = await insertBatch('stage_history', STAGE_HISTORY);

    // 4. Insert comments
    const commentCount = await insertBatch('comments', COMMENTS);

    // 5. Insert service_descriptions
    const sowCount = await insertBatch('service_descriptions', SERVICE_DESCRIPTIONS);

    return res.status(201).json({
      message: 'Database seeded successfully',
      counts: {
        users: userCount,
        requests: requestCount,
        stage_history: stageCount,
        comments: commentCount,
        service_descriptions: sowCount,
      },
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    console.error('Seed error:', message);
    return res.status(500).json({ error: message });
  }
}
